#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, Z;
        scanf("%lld %lld %lld", &X, &Y, &Z);
        long long profit = X * (Z - Y);
        printf("%lld\n", profit);
    }
    return 0;
}

